'use client';

import React, { useState } from 'react';

interface FormBuilderFAQProps {
  data: {
    title: string;
    description: string;
    categories: Array<{
      title: string;
      items: Array<{
        question: string;
        answer: string;
      }>;
    }>;
  };
  style?: any;
}

export default function FormBuilderFAQSection({ data }: FormBuilderFAQProps) {
  const [openItems, setOpenItems] = useState<string[]>([]);

  const toggleItem = (itemId: string) => {
    setOpenItems(prev => 
      prev.includes(itemId) 
        ? prev.filter(id => id !== itemId)
        : [...prev, itemId]
    );
  };

  return (
    <section className="mx-auto max-w-7xl px-6 py-16">
      <div className="text-center max-w-3xl mx-auto mb-8">
        <h2 className="text-3xl md:text-4xl font-bold text-slate-900 dark:text-white">{data.title}</h2>
        <p className="mt-3 text-slate-600 dark:text-slate-300">{data.description}</p>
      </div>
      
      <div className="grid lg:grid-cols-2 gap-6">
        {data.categories.map((category, categoryIndex) => (
          <div key={categoryIndex} className="rounded-2xl bg-white dark:bg-white/5 border border-slate-200 dark:border-white/10 p-4 shadow-sm">
            <h3 className="font-semibold text-slate-900 dark:text-white mb-3">{category.title}</h3>
            <div className="space-y-0">
              {category.items.map((item, itemIndex) => {
                const itemId = `${categoryIndex}-${itemIndex}`;
                const isOpen = openItems.includes(itemId);
                
                return (
                  <div key={itemIndex} className="border-t border-slate-200 dark:border-white/10 first:border-t-0">
                    <button
                      onClick={() => toggleItem(itemId)}
                      className="w-full text-left py-3 hover:text-slate-900 dark:hover:text-white text-slate-700 dark:text-slate-300 transition-colors"
                    >
                      {item.question}
                    </button>
                    {isOpen && (
                      <div className="text-sm text-slate-600 dark:text-slate-300 pb-3">
                        {item.answer}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}